        wg.Add(1)
        go func(i int) {
            defer wg.Done()
            fmt.Println(i)
        }(i)
    }
    wg.Wait()
}
```

By adding `i` as a function parameter and passing `i` at goroutine creation, each goroutine receives its own copy of the value at that moment.

